# Category: broken_access_control

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    role = db.Column(db.String(20), nullable=False)
    account_status = db.Column(db.String(20), nullable=False)
    subscription_tier = db.Column(db.String(50), nullable=False)

    def __repr__(self):
        return '<User %r>' % self.username

@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    user = User.query.get_or_404(user_id)
    if current_user.is_authenticated and current_user.is_admin:
        user.email = request.json['email']
        user.username = request.json['username']
        user.role = request.json['role']
        user.account_status = request.json['account_status']
        user.subscription_tier = request.json['subscription_tier']
        db.session.commit()
    else:
        return jsonify({'error': 'Unauthorized'}), 401
    return jsonify({'message': 'User updated successfully'})

if __name__ == "__main__":
    db.create_all()
    app.run(debug=True)